                            start = max(0, i - 3)
                            end = min(len(lines), i + 2)
                            context_lines = []
                            for j in range(start, end):
                                prefix = ">>> " if j == i-1 else "    "
                                context_lines.append(f"{prefix}{j+1:4d}: {lines[j]}", )
                            results.append({
